import re

# Load the Newick tree from a file
with open("/Users/user/Documents/PlantProject/HCP_v2_results/PAML_free_branch/w_tree_2.nwk", "r") as file:
    tree_w = file.read().strip()

# Step 1: Extract tip and internal branch omega values
tip_omega = {}
internal_omega = {}
tip_names = set()

# Process tip omega values
matches = re.findall(r"(\w+)\s+#([\d\.]+)", tree_w)
for match in matches:
    taxon, omega = match
    tip_omega[taxon] = omega
    tip_names.add(taxon)

# Process internal branch omega values
matches = re.findall(r"(\))\s+#([\d\.]+)", tree_w)
branch_counter = 1  # Unique ID for internal nodes
for match in matches:
    _, omega = match
    internal_omega[f"node{branch_counter}"] = omega
    branch_counter += 1

# Remove all `#omega_value` from the Newick tree for proper Nexus conversion
tree_w = re.sub(r"#([\d\.]+)", "", tree_w)

# Generate the Nexus format output
nexus_output = "#NEXUS\n\nBEGIN TREES;\n"
nexus_output += f"   TREE tree1 = {tree_w}\nEND;\n\n"

# Add omega values to a TRAITS block for coloring
nexus_output += "BEGIN TRAITS;\n"
nexus_output += "   Dimensions NTRAITS=1;\n"
nexus_output += "   TraitLabels omega;\n"
nexus_output += "   Matrix\n"

# Tip trait values
for taxon in tip_names:
    omega_value = tip_omega.get(taxon, "0.0")  # Default to 0.0 if missing
    nexus_output += f"   {taxon} {omega_value}\n"

# Internal node trait values
for node_id, omega_value in internal_omega.items():
    nexus_output += f"   {node_id} {omega_value}\n"

nexus_output += "   ;\nEND;\n"

# Save the corrected Nexus tree file
with open("/Users/user/Documents/PlantProject/HCP_v2_results/PAML_free_branch/figtree_tree.nex", "w", encoding="utf-8") as file:
    file.write(nexus_output)

print("Conversion complete! Open 'figtree_tree.nex' in FigTree.")






